{
  "terms": [
    {
      "term": "Atom",
      "simpleDefinition": "The basic building block of all matter, consisting of a central nucleus and orbiting electrons.",
      "anchor": "Think of it like a tiny solar system with a sun at the center and planets orbiting around it.",
      "misconception": "Thinking that atoms are only found in certain materials; in reality, everything in an electrical installation is made of atoms."
    },
    {
      "term": "Nucleus",
      "simpleDefinition": "The heavy center of an atom containing protons and neutrons; it stays stationary during electrical flow.",
      "anchor": "The 'engine room' at the center that holds the atom together.",
      "misconception": "Believing the nucleus moves when electricity flows; only the electrons move."
    },
    {
      "term": "Electron",
      "simpleDefinition": "A tiny, negatively charged particle that orbits the nucleus of an atom.",
      "anchor": "The 'planets' orbiting the nucleus that carry the electrical charge.",
      "misconception": "Thinking electrons are stationary; they are constantly orbiting at high speeds."
    },
    {
      "term": "Valence Shell",
      "simpleDefinition": "The outermost orbit or 'ring' of an atom where electrons are most likely to be knocked loose.",
      "anchor": "The outer boundary of the atom where all the electrical 'action' happens.",
      "misconception": "Thinking all electrons in an atom contribute to electricity; only those in the valence shell are involved."
    },
    {
      "term": "Free Electron",
      "simpleDefinition": "A valence electron that has broken away from its atom and is able to move through a material.",
      "anchor": "The 'drifters' that move from atom to atom to create an electric current.",
      "misconception": "Thinking all electrons are free; in many materials, they are locked tight to their atoms."
    },
    {
      "term": "Conductor",
      "simpleDefinition": "A material, usually a metal, that has a large number of free electrons allowing electricity to flow easily.",
      "anchor": "The copper core of a standard twin and earth cable.",
      "misconception": "Believing that a conductor 'creates' electricity; it simply provides the path for free electrons to move."
    },
    {
      "term": "Insulator",
      "simpleDefinition": "A material where electrons are tightly bound to their atoms, preventing the flow of electricity.",
      "anchor": "The PVC (plastic) colored coating on the outside of a wire.",
      "misconception": "Thinking insulators have no electrons at all; they have plenty, but the electrons are not 'free' to move."
    }
  ],
  "anchorPhrases": [
    "Electricity is the flow of free electrons.",
    "Conductors have plenty of free electrons.",
    "Insulators hold their electrons tight.",
    "The valence shell is the outermost ring.",
    "The nucleus stays put; the electrons do the work."
  ],
  "misconceptionTargets": [
    "Insulators contain zero electrons.",
    "The nucleus of an atom moves through a wire during current flow.",
    "All electrons in a copper wire are free electrons.",
    "Valence electrons are found in the center of the atom."
  ]
}

{
  "teachChecks": [
    {
      "title": "Basic Electron Theory",
      "objective": "Explain the structure of an atom and the role of valence electrons in electrical flow.",
      "retrievalTextLines": [
        "To understand electricity, we must look at the atom, the building block of all matter. Every material in an installation, from a copper conductor to a PVC sheath, is made of atoms. At the center of an atom is the nucleus, containing protons and neutrons. This nucleus is heavy and stays stationary; it does not move through the wire during electrical flow.",
        "Orbiting this nucleus are tiny, negatively charged particles called electrons. These electrons travel in specific layers or 'shells' at high speeds. The most important layer for an electrician is the valence shell, which is the outermost ring of the atom. Electrical current is created when electrons in this valence shell are pushed out of their orbit.",
        "Once an electron is knocked loose from the valence shell, it is known as a free electron. These free electrons are the 'drifters' that move from atom to atom, carrying the electrical charge through a circuit. In electrical science, the nucleus stays put while the electrons do the work of moving the energy."
      ],
      "hint": "Focus on the outermost ring of the atom and the specific particles that are able to move."
    },
    {
      "title": "Conductors vs Insulators",
      "objective": "Distinguish between conductors and insulators based on the presence of free electrons.",
      "retrievalTextLines": [
        "Materials are classified as either conductors or insulators based on how easily their electrons can move. A conductor, such as copper, gold, or aluminum, is a material that has a large number of free electrons. In these metals, the valence electrons are loosely bound to the nucleus, meaning they can easily break away and drift through the material. This provides the path for electricity to flow.",
        "In contrast, an insulator is a material where the electrons are held tightly to their atoms. Common insulators include PVC (plastic), rubber, and glass. It is a misconception to think insulators have no electrons; they have plenty, but the electrons are 'locked' in place and are not free to move. Because they lack free electrons, these materials prevent the flow of electricity.",
        "Electricians use these properties to control energy. We use the copper core of a cable as a conductor to carry current, and we wrap it in a PVC insulator to ensure the current stays within the wire and does not cause a shock or a fire."
      ],
      "hint": "Think about whether the electrons are 'free' to move or 'tightly bound' to the atom."
    }
  ]
}

{
  "teachChecks": [
    {
      "title": "Basic Electron Theory",
      "basicQuestions": [
        {
          "questionText": "What is the name of the outermost ring or shell of an atom?",
          "answerGuidance": [
            "Valence shell",
            "Outermost orbit",
            "The ring where electrons are knocked loose"
          ]
        },
        {
          "questionText": "Which part of the atom contains protons and neutrons and remains stationary during electrical flow?",
          "answerGuidance": [
            "Nucleus",
            "The center of the atom",
            "The heavy stationary part"
          ]
        },
        {
          "questionText": "What is the specific term for an electron that has broken away from its orbit and is able to move through a material?",
          "answerGuidance": [
            "Free electron",
            "A drifter",
            "An electron carrying electrical charge"
          ]
        }
      ],
      "deeperQuestionText": "Why is the valence shell considered the most important part of the atom for an electrician?",
      "deeperAnswerGuidance": [
        "It is the only shell where electrons can be pushed out of orbit",
        "Electricity is the flow of free electrons",
        "Inner shell electrons are held too tightly to move",
        "The valence shell is where the electrical action happens"
      ],
      "hint": "Focus on the outermost ring of the atom and the specific particles that are able to move."
    },
    {
      "title": "Conductors vs Insulators",
      "basicQuestions": [
        {
          "questionText": "What type of material is defined by having a large number of free electrons?",
          "answerGuidance": [
            "Conductor",
            "Metals like copper or aluminum",
            "Materials with loosely bound valence electrons"
          ]
        },
        {
          "questionText": "Name two common materials used as insulators in electrical installations.",
          "answerGuidance": [
            "PVC",
            "Rubber",
            "Glass",
            "Plastic"
          ]
        },
        {
          "questionText": "In an insulator, how are the electrons held in relation to the nucleus?",
          "answerGuidance": [
            "Tightly bound",
            "Locked in place",
            "Not free to move"
          ]
        }
      ],
      "deeperQuestionText": "If an insulator like PVC contains many electrons, why can it not be used to carry an electric current?",
      "deeperAnswerGuidance": [
        "Current requires the movement of free electrons",
        "Insulators lack free electrons",
        "The electrons in PVC are tightly bound to their atoms",
        "The electrons cannot break away to drift through the material"
      ],
      "hint": "Think about whether the electrons are 'free' to move or 'tightly bound' to the atom."
    }
  ]
}

{
  "guidedPractice": {
    "title": "Guided Practice",
    "objective": "Categorize common installation materials as conductors or insulators based on their electron behavior.",
    "retrievalTextLines": [
      "Recall the Twin and Earth example: we look at the valence shell to see if electrons are 'free' or 'locked'.",
      "Step 1: Analyze the Gold terminal. Gold atoms have a valence shell where electrons are loosely bound and easily become free electrons.",
      "Step 2: Analyze the Rubber grommet. Rubber atoms have valence electrons that are tightly bound to the nucleus and cannot move.",
      "Step 3: Classify the materials based on these atomic properties."
    ],
    "questionText": "You are installing high-end audio equipment using gold-plated terminals and rubber grommets. Based on electron theory: 1. Why is gold used for the connection? 2. Why does the rubber grommet prevent a short circuit to the metal casing?",
    "answerGuidance": [
      "Gold is a conductor because its valence shell allows for many free electrons.",
      "Rubber is an insulator because its valence electrons are tightly bound and cannot flow."
    ],
    "hint": "Focus on whether the valence electrons are 'loosely bound' (free to move) or 'tightly bound' (locked in place)."
  },
  "practice": {
    "title": "Practice",
    "objective": "Verify the ability to describe electron movement and identify material types in a professional context.",
    "retrievalTextLines": [
      "In any electrical system, the movement of charge depends entirely on the atomic structure of the materials used.",
      "Conductors provide the path; insulators provide the barrier.",
      "This is determined by the availability of free electrons in the outermost shell."
    ],
    "questionText": "An apprentice asks you why an aluminum busbar is used to carry power in a distribution board, but the supports holding it are made of glass-reinforced plastic (GRP). Explain the difference between these two materials using the terms 'valence shell' and 'free electrons'.",
    "answerGuidance": [
      "Aluminum is a conductor because its valence shell allows for the movement of free electrons.",
      "GRP is an insulator because its valence shell holds electrons tightly, meaning there are no free electrons to carry current."
    ],
    "hint": "Explain what happens in the valence shell of each material and whether that results in 'free electrons'."
  }
}

{
  "integrative": {
    "title": "Integrative Close: The Anatomy of a Cable",
    "objective": "Connect atomic theory to the physical construction of a standard electrical cable, identifying which parts are conductors and which are insulators.",
    "retrievalTextLines": [
      "In a standard electrical cable, we use different materials to control the flow of energy safely.",
      "The core of the cable must allow electricity to pass through, while the outer sheath must block it.",
      "This physical design is entirely dependent on the atomic structure of the materials chosen."
    ],
    "questionText": "Consider a standard 2.5mm² Twin and Earth cable. Using your knowledge of electron theory, explain why the copper core is used to carry the current while the PVC (plastic) insulation is used to cover it. Your answer must specifically mention the 'valence shell' and the presence or absence of 'free electrons' in both materials.",
    "answerGuidance": [
      "Copper is a conductor because its valence shell allows electrons to be loosely bound, resulting in a high number of free electrons that can move to create current.",
      "PVC is an insulator because its valence shell holds electrons tightly to the nucleus, meaning there are no free electrons available to carry a charge.",
      "The nucleus of the atoms in both materials remains stationary; only the free electrons in the copper move through the circuit."
    ],
    "hint": "Think about which material has 'loose' electrons in its outermost shell and which one has 'locked' electrons."
  }
}

